1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
16	
17	export const nextGeneration = (cells: Cell[]): Cell[] => {
18	  const liveCells = new Map<string, Cell>(cells.map((cell) => [keyOf(cell), cell]));
19	
20	  const candidates = new Map<string, Cell>(liveCells);
21	  for (const cell of cells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      candidates.set(keyOf(neighbor), neighbor);
24	    }
25	  }
26	
27	  const countLiveNeighbors = (cell: Cell): number =>
28	    neighborsOf(cell).reduce(
29	      (count, neighbor) => count + (liveCells.has(keyOf(neighbor)) ? 1 : 0),
30	      0,
31	    );
32	
33	  const result: Cell[] = [];
34	  for (const [key, cell] of candidates) {
35	    if (survives(liveCells.has(key), countLiveNeighbors(cell))) {
36	      result.push(cell);
37	    }
38	  }
39	  return result;
40	};
